            strcpy(current_pos, label_values[i]);
            current_pos += value_len;

            // Write closing "
            *current_pos++ = '"';
        }

        // Add closing brace
        *current_pos++ = '}';
    }

    // Null-terminate the string
    *current_pos = '\0';

    return current_pos - metric_output;
}
